const COUNTRIES = {
  // ─── EUROPE ───────────────────────────────────
  "8":   { name:"Albania",        capital:"Tirana",              iso2:"al", continent:"europe", summary:"Albania is a small country in southeastern Europe on the Adriatic and Ionian coasts. It has a rich ancient history, was once isolated under communist rule until 1991, and is now a parliamentary republic and NATO member aspiring to join the EU." },
  "20":  { name:"Andorra",        capital:"Andorra la Vella",    iso2:"ad", continent:"europe", summary:"Andorra is a tiny principality in the Pyrenees between France and Spain. It is one of Europe's smallest and wealthiest nations per capita, known for ski tourism and duty-free shopping. The co-princes are the French President and the Bishop of Urgell." },
  "40":  { name:"Austria",        capital:"Vienna",              iso2:"at", continent:"europe", summary:"Austria is a landlocked country in Central Europe, famous for its Alpine landscapes, classical music heritage (Mozart, Beethoven) and the historic Austro-Hungarian Empire. Vienna, its capital, is consistently ranked among the world's most liveable cities." },
  "56":  { name:"Belgium",        capital:"Brussels",            iso2:"be", continent:"europe", summary:"Belgium is a small but densely populated country in Western Europe, home to the headquarters of the EU and NATO. It is known for its chocolate, waffles, beer and the medieval cities of Bruges and Ghent. It has three official languages: Dutch, French and German." },
  "70":  { name:"Bosnia and Herzegovina", capital:"Sarajevo",   iso2:"ba", continent:"europe", summary:"Bosnia and Herzegovina is a Balkan country with a complex ethnic and political structure following the 1992–1995 war. Sarajevo, its capital, hosted the 1984 Winter Olympics and is famous for its rich Ottoman and Austro-Hungarian heritage." },
  "100": { name:"Bulgaria",       capital:"Sofia",               iso2:"bg", continent:"europe", summary:"Bulgaria is a country in southeastern Europe on the Black Sea coast with a 1,300-year history. A member of the EU since 2007, it is known for the Cyrillic alphabet (invented here), rose oil production and ancient Thracian treasures." },
  "191": { name:"Croatia",        capital:"Zagreb",              iso2:"hr", continent:"europe", summary:"Croatia is an Adriatic nation in southeastern Europe famous for its stunning Dalmatian coastline, crystal-clear sea and numerous islands. A member of the EU since 2013, it is also renowned for its medieval walled city of Dubrovnik." },
  "196": { name:"Cyprus",         capital:"Nicosia",             iso2:"cy", continent:"europe", summary:"Cyprus is an island nation in the eastern Mediterranean and the third-largest island in the sea. It is divided since 1974 between the Republic of Cyprus (EU member) in the south and the Turkish-controlled north. It is known for tourism and financial services." },
  "203": { name:"Czech Republic", capital:"Prague",              iso2:"cz", continent:"europe", summary:"The Czech Republic (Czechia) is a landlocked Central European country. Prague, its capital, is one of Europe's most beautiful cities with a well-preserved medieval Old Town. The country has a strong industrial and cultural tradition and joined the EU in 2004." },
  "208": { name:"Denmark",        capital:"Copenhagen",          iso2:"dk", continent:"europe", summary:"Denmark is a Scandinavian kingdom consisting of the Jutland peninsula and numerous islands. It is one of the world's happiest and most egalitarian societies, consistently leading global rankings for quality of life, democracy and sustainability." },
  "233": { name:"Estonia",        capital:"Tallinn",             iso2:"ee", continent:"europe", summary:"Estonia is a small Baltic country on the Gulf of Finland, one of the world's most digitally advanced societies. Tallinn's medieval Old Town is a UNESCO World Heritage Site. Estonia joined NATO and the EU in 2004 and was the first country to hold national elections online." },
  "246": { name:"Finland",        capital:"Helsinki",            iso2:"fi", continent:"europe", summary:"Finland is a Nordic country known for its vast forests, thousands of lakes and the Northern Lights. It has one of the world's best education systems. Finland joined NATO in 2023 following Russia's invasion of Ukraine, ending decades of military non-alignment." },
  "250": { name:"France",         capital:"Paris",               iso2:"fr", continent:"europe", summary:"France is one of the world's leading nations, known for its culture, cuisine, fashion and art. Paris, the capital, is home to the Eiffel Tower and the Louvre. France is a founding member of the EU, a permanent member of the UN Security Council and a nuclear power." },
  "276": { name:"Germany",        capital:"Berlin",              iso2:"de", continent:"europe", summary:"Germany is Europe's largest economy and a key player in global politics. Reunified in 1990 after 45 years of division, it is a federal parliamentary republic. Berlin, its capital, is known for its vibrant culture, turbulent history and thriving startup scene." },
  "300": { name:"Greece",         capital:"Athens",              iso2:"gr", continent:"europe", summary:"Greece is the birthplace of Western civilization, democracy and the Olympics. Athens, one of the world's oldest cities, is home to the Parthenon. Greece has stunning Aegean islands, a rich mythology and joined the EU in 1981." },
  "348": { name:"Hungary",        capital:"Budapest",            iso2:"hu", continent:"europe", summary:"Hungary is a landlocked Central European nation with a unique non-Indo-European language. Budapest, split by the Danube into Buda and Pest, is celebrated for its thermal baths and stunning parliament building. Hungary joined the EU in 2004." },
  "352": { name:"Iceland",        capital:"Reykjavík",           iso2:"is", continent:"europe", summary:"Iceland is a North Atlantic island nation of volcanic landscapes, geysers, hot springs and lava fields. It is one of the most sparsely populated countries in Europe and has one of the highest standards of living, powered almost entirely by renewable energy." },
  "372": { name:"Ireland",        capital:"Dublin",              iso2:"ie", continent:"europe", summary:"Ireland is an island nation in the North Atlantic with a rich Celtic heritage. Known for its green countryside, literary tradition (Joyce, Yeats, Beckett) and strong diaspora, Ireland is a major hub for multinational technology companies and an EU member since 1973." },
  "380": { name:"Italy",          capital:"Rome",                iso2:"it", continent:"europe", summary:"Italy is a Mediterranean country with an extraordinary artistic and historical heritage. Home to the Vatican, the Colosseum, Venice and the Renaissance, it is the world's top cultural destination. Italy is also renowned for its fashion, cuisine and design." },
  "428": { name:"Latvia",         capital:"Riga",                iso2:"lv", continent:"europe", summary:"Latvia is a Baltic state on the eastern shore of the Baltic Sea. Riga, its capital, is the largest city in the Baltics and a UNESCO World Heritage Site for its Art Nouveau architecture. Latvia joined NATO and the EU in 2004." },
  "438": { name:"Liechtenstein",  capital:"Vaduz",               iso2:"li", continent:"europe", summary:"Liechtenstein is one of Europe's smallest countries, a constitutional monarchy nestled between Switzerland and Austria. Despite its tiny size it has one of the world's highest GDP per capita and is a major financial centre. It uses the Swiss franc and has no army." },
  "440": { name:"Lithuania",      capital:"Vilnius",             iso2:"lt", continent:"europe", summary:"Lithuania is the largest of the three Baltic states and the first Soviet republic to declare independence in 1990. Vilnius has a remarkable baroque Old Town. Lithuania is a NATO and EU member and one of the fastest-growing economies in the EU." },
  "442": { name:"Luxembourg",     capital:"Luxembourg",          iso2:"lu", continent:"europe", summary:"Luxembourg is a tiny Grand Duchy sandwiched between Belgium, France and Germany, and one of the founding members of the EU. Despite its small size it is one of the world's wealthiest countries per capita, with a major financial sector." },
  "470": { name:"Malta",          capital:"Valletta",            iso2:"mt", continent:"europe", summary:"Malta is a small archipelago in the Mediterranean with a history going back over 7,000 years. It has the world's smallest EU capital in Valletta, a UNESCO World Heritage Site. Malta is known for its megalithic temples, clear waters and English-speaking population." },
  "498": { name:"Moldova",        capital:"Chișinău",            iso2:"md", continent:"europe", summary:"Moldova is one of Europe's poorest countries, a landlocked nation between Romania and Ukraine. It declared independence from the Soviet Union in 1991 and has close cultural ties with Romania. It applied for EU membership in 2022." },
  "492": { name:"Monaco",         capital:"Monaco",              iso2:"mc", continent:"europe", summary:"Monaco is a tiny city-state on the French Riviera, the world's second-smallest country by area. It is famous for its casino, the Formula 1 Grand Prix and the highest density of millionaires in the world. Its official language is French." },
  "499": { name:"Montenegro",     capital:"Podgorica",           iso2:"me", continent:"europe", summary:"Montenegro is a small Adriatic nation that gained independence from Serbia in 2006. It is known for its dramatic mountain scenery, medieval walled towns and the Bay of Kotor. Montenegro is a NATO member and is negotiating EU accession." },
  "528": { name:"Netherlands",    capital:"Amsterdam",           iso2:"nl", continent:"europe", summary:"The Netherlands is a densely populated lowland country famous for windmills, tulips, cycling and liberal social policies. Amsterdam is a world-class cultural capital. The Netherlands is a founding EU member and home to major international organizations in The Hague." },
  "807": { name:"North Macedonia",capital:"Skopje",              iso2:"mk", continent:"europe", summary:"North Macedonia is a landlocked Balkan country that declared independence from Yugoslavia in 1991. It joined NATO in 2020 after changing its name from 'Macedonia' in agreement with Greece, and is a candidate for EU membership." },
  "578": { name:"Norway",         capital:"Oslo",                iso2:"no", continent:"europe", summary:"Norway is a Scandinavian country known for its dramatic fjords, Northern Lights and the midnight sun. One of the world's wealthiest nations, it has a massive sovereign wealth fund from North Sea oil. Norway is a NATO member but has chosen not to join the EU." },
  "616": { name:"Poland",         capital:"Warsaw",              iso2:"pl", continent:"europe", summary:"Poland is a Central European country with a turbulent history of partitions, occupation and rebuilding. It has been one of the EU's fastest-growing economies since joining in 2004. Warsaw was almost entirely destroyed in WWII and was meticulously rebuilt." },
  "620": { name:"Portugal",       capital:"Lisbon",              iso2:"pt", continent:"europe", summary:"Portugal is a seafaring nation on the western edge of Europe that built one of history's greatest empires. Lisbon is a city of hills, trams and Fado music. Portugal is known for its custard tarts, wine, cork production and 300 days of sunshine per year." },
  "642": { name:"Romania",        capital:"Bucharest",           iso2:"ro", continent:"europe", summary:"Romania is a Balkan country known for the Carpathian mountains, the Danube Delta and Transylvania. Bucharest was once called 'Little Paris'. Romania joined the EU in 2007 and has seen rapid economic growth in recent decades." },
  "643": { name:"Russia",         capital:"Moscow",              iso2:"ru", continent:"europe", summary:"Russia is the world's largest country by area, spanning 11 time zones from Eastern Europe to the Pacific. Moscow, its capital, and Saint Petersburg are major cultural centres. Russia is a permanent UN Security Council member and a major nuclear power." },
  "674": { name:"San Marino",     capital:"San Marino",          iso2:"sm", continent:"europe", summary:"San Marino is the world's oldest republic, founded in 301 AD, entirely surrounded by Italy. It is the world's fifth-smallest country, governed by two Captains Regent elected every six months. It claims to be the world's first constitutional republic." },
  "688": { name:"Serbia",         capital:"Belgrade",            iso2:"rs", continent:"europe", summary:"Serbia is a landlocked Balkan country that was the core of Yugoslavia. Belgrade, at the confluence of the Sava and Danube rivers, is one of Europe's oldest cities and a major nightlife destination. Serbia is an EU candidate country." },
  "703": { name:"Slovakia",       capital:"Bratislava",          iso2:"sk", continent:"europe", summary:"Slovakia is a landlocked Central European country that peacefully separated from Czechoslovakia in 1993 (the Velvet Divorce). Bratislava, on the Danube near Vienna and Budapest, is known for its compact but charming old town. Slovakia is an EU and NATO member." },
  "705": { name:"Slovenia",       capital:"Ljubljana",           iso2:"si", continent:"europe", summary:"Slovenia is a small Alpine country at the crossroads of Central Europe and the Balkans. It was the first former Yugoslav republic to join the EU (2004). Known for its pristine Lake Bled, Triglav National Park and sustainable tourism." },
  "724": { name:"Spain",          capital:"Madrid",              iso2:"es", continent:"europe", summary:"Spain is a vibrant Mediterranean country on the Iberian Peninsula known for its diverse regions, flamenco, tapas and architectural gems like the Sagrada Família. Madrid and Barcelona are world-class cultural capitals. Spain is a constitutional monarchy and founding NATO member." },
  "752": { name:"Sweden",         capital:"Stockholm",           iso2:"se", continent:"europe", summary:"Sweden is a Scandinavian monarchy renowned for its progressive social policies, environmental leadership and design. Stockholm, built on 14 islands, is home to the Nobel Prize ceremonies. Sweden joined NATO in 2024 after Russia's invasion of Ukraine." },
  "756": { name:"Switzerland",    capital:"Bern",                iso2:"ch", continent:"europe", summary:"Switzerland is a landlocked Alpine confederation known for its political neutrality, banking secrecy, precision watches and stunning mountain scenery. Geneva hosts major international organizations. Switzerland has four official languages: German, French, Italian and Romansh." },
  "804": { name:"Ukraine",        capital:"Kyiv",                iso2:"ua", continent:"europe", summary:"Ukraine is the largest country entirely within Europe, with a rich history dating back to the Kyivan Rus. Since Russia's full-scale invasion in February 2022, it has been fighting to defend its sovereignty. Kyiv is one of Europe's oldest cities." },
  "826": { name:"United Kingdom", capital:"London",              iso2:"gb", continent:"europe", summary:"The United Kingdom comprises England, Scotland, Wales and Northern Ireland. London is one of the world's most important financial and cultural capitals. The UK left the EU in 2020 (Brexit) and is home to the world's oldest constitutional monarchy." },
  "336": { name:"Vatican City",   capital:"Vatican City",        iso2:"va", continent:"europe", summary:"Vatican City is the world's smallest country by both area and population, an independent city-state within Rome. It is the headquarters of the Roman Catholic Church and the Pope's residence. Home to St. Peter's Basilica and the Sistine Chapel." },
  "383": { name:"Kosovo",         capital:"Pristina",            iso2:"xk", continent:"europe", summary:"Kosovo declared independence from Serbia in 2008 and is recognised by over 100 countries, though not by Serbia, Russia or China. It is one of Europe's youngest nations, with a predominantly Albanian population and a strong cultural identity." },

  // ─── AFRICA ───────────────────────────────────
  "12":  { name:"Algeria",        capital:"Algiers",             iso2:"dz", continent:"africa", summary:"Algeria is Africa's largest country, mostly covered by the Sahara Desert. It gained independence from France in 1962 after a brutal war. Algeria is a major oil and gas producer and an important player in North African and Arab world politics." },
  "24":  { name:"Angola",         capital:"Luanda",              iso2:"ao", continent:"africa", summary:"Angola is a large oil-rich country in southwestern Africa that emerged from a devastating 27-year civil war ending in 2002. Luanda is one of Africa's most expensive cities. The country has significant mineral wealth including diamonds and oil." },
  "204": { name:"Benin",          capital:"Porto-Novo",          iso2:"bj", continent:"africa", summary:"Benin is a small West African country known as the birthplace of Vodou. The historic city of Abomey was capital of the ancient Dahomey Kingdom. Benin was one of the first African countries to transition peacefully to multi-party democracy." },
  "72":  { name:"Botswana",       capital:"Gaborone",            iso2:"bw", continent:"africa", summary:"Botswana is a landlocked country in southern Africa that transformed itself from one of the world's poorest nations at independence in 1966 to a middle-income country thanks to diamond mining. The Okavango Delta is one of Africa's greatest wildlife destinations." },
  "854": { name:"Burkina Faso",   capital:"Ouagadougou",         iso2:"bf", continent:"africa", summary:"Burkina Faso is a landlocked Sahel nation in West Africa that struggles with poverty and jihadist insurgency. Despite challenges it has a rich culture expressed through its famous FESPACO pan-African film festival, the largest in Africa." },
  "108": { name:"Burundi",        capital:"Gitega",              iso2:"bi", continent:"africa", summary:"Burundi is a small, densely populated landlocked country in East Africa, one of the world's poorest. It has experienced ethnic conflict between Hutu and Tutsi peoples. Its constitutional capital was moved from Bujumbura to Gitega in 2019." },
  "120": { name:"Cameroon",       capital:"Yaoundé",             iso2:"cm", continent:"africa", summary:"Cameroon is described as 'Africa in miniature' for its extraordinary geographic and cultural diversity, from rainforests to savannah to Sahel. It has 250 languages and a bilingual (French/English) system inherited from colonial rule." },
  "132": { name:"Cape Verde",     capital:"Praia",               iso2:"cv", continent:"africa", summary:"Cape Verde is an archipelago of 10 volcanic islands in the central Atlantic off the coast of West Africa. A former Portuguese colony, it is one of Africa's most stable democracies and is known for its musical style Morna and beautiful beaches." },
  "140": { name:"Central African Republic", capital:"Bangui",    iso2:"cf", continent:"africa", summary:"The Central African Republic is a landlocked country in the heart of Africa with vast natural resources but severe political instability and armed conflict. It is consistently ranked among the world's least developed countries." },
  "148": { name:"Chad",           capital:"N'Djamena",           iso2:"td", continent:"africa", summary:"Chad is a landlocked country in north-central Africa, straddling the Sahara and sub-Saharan zones. It contains the shrinking Lake Chad, which once was one of Africa's largest lakes. Chad faces chronic poverty, political instability and regional conflict." },
  "174": { name:"Comoros",        capital:"Moroni",              iso2:"km", continent:"africa", summary:"Comoros is a small Indian Ocean archipelago off Africa's east coast, one of the world's poorest nations. It is the only country in the world that is a member of the African Union, Arab League and Organisation of Islamic Cooperation simultaneously." },
  "178": { name:"Republic of the Congo", capital:"Brazzaville",  iso2:"cg", continent:"africa", summary:"The Republic of the Congo (Congo-Brazzaville) is a Central African nation rich in oil. Its capital Brazzaville sits directly across the Congo River from Kinshasa, making them the world's two closest capital cities of independent nations." },
  "180": { name:"DR Congo",       capital:"Kinshasa",            iso2:"cd", continent:"africa", summary:"The Democratic Republic of Congo is Africa's largest country south of the Sahara, with vast mineral wealth including coltan, gold and diamonds. Despite its resources it is one of the world's poorest countries, scarred by decades of conflict and instability." },
  "262": { name:"Djibouti",       capital:"Djibouti",            iso2:"dj", continent:"africa", summary:"Djibouti is a tiny strategic nation at the entrance to the Red Sea, one of the world's most important shipping lanes. It hosts multiple foreign military bases including those of the US, France, China and Japan, making it a geopolitically vital country." },
  "818": { name:"Egypt",          capital:"Cairo",               iso2:"eg", continent:"africa", summary:"Egypt is one of the world's oldest civilizations, home to the Pyramids, the Sphinx and the Nile. Cairo is Africa's largest city. Egypt controls the Suez Canal, one of the world's most important maritime passages. It is the Arab world's most populous nation." },
  "226": { name:"Equatorial Guinea", capital:"Malabo",           iso2:"gq", continent:"africa", summary:"Equatorial Guinea is one of sub-Saharan Africa's main oil producers, which gave it one of the continent's highest per capita incomes—but with extreme inequality. It is Africa's only sovereign state with Spanish as an official language, plus French and Portuguese." },
  "232": { name:"Eritrea",        capital:"Asmara",              iso2:"er", continent:"africa", summary:"Eritrea is a small Northeast African nation on the Red Sea that gained independence from Ethiopia in 1993 after a 30-year war. Asmara, known as 'Little Rome', has exceptional Italian colonial-era Art Deco architecture. The country has been largely closed off under authoritarian rule." },
  "231": { name:"Ethiopia",       capital:"Addis Ababa",         iso2:"et", continent:"africa", summary:"Ethiopia is Africa's oldest independent country and its second most populous, with over 120 million inhabitants. It is the headquarters of the African Union. Ethiopia was never colonized (except briefly by Italy), making it a symbol of African independence." },
  "266": { name:"Gabon",          capital:"Libreville",          iso2:"ga", continent:"africa", summary:"Gabon is an oil-rich Central African nation covered by vast equatorial rainforests that are home to forest elephants and western lowland gorillas. Despite its resources, wealth is unevenly distributed. A military coup took place in 2023." },
  "270": { name:"Gambia",         capital:"Banjul",              iso2:"gm", continent:"africa", summary:"The Gambia is Africa's smallest mainland country, a narrow strip of land along the Gambia River surrounded on three sides by Senegal. A major tourist destination for Europeans, it is known for its beaches, birdwatching and vibrant culture." },
  "288": { name:"Ghana",          capital:"Accra",               iso2:"gh", continent:"africa", summary:"Ghana was the first sub-Saharan African country to gain independence (1957), under Kwame Nkrumah. Known as the 'Gateway to Africa', it has a stable democracy, cocoa and gold exports, and a rich cultural heritage including the Ashanti Kingdom." },
  "324": { name:"Guinea",         capital:"Conakry",             iso2:"gn", continent:"africa", summary:"Guinea is a West African nation with one of the world's largest bauxite reserves. It gained independence from France in 1958 as the first Francophone African nation to do so. The country has experienced several coups and political instability." },
  "624": { name:"Guinea-Bissau",  capital:"Bissau",              iso2:"gw", continent:"africa", summary:"Guinea-Bissau is a small West African country and one of the world's poorest nations. It gained independence from Portugal in 1974 and has experienced chronic political instability. The country includes the Bijagós Archipelago, a UNESCO Biosphere Reserve." },
  "384": { name:"Ivory Coast",    capital:"Yamoussoukro",        iso2:"ci", continent:"africa", summary:"Ivory Coast (Côte d'Ivoire) is the world's largest producer of cocoa and a major economic power in West Africa. Its largest city and business capital is Abidjan, while Yamoussoukro is the official capital, home to the world's largest church." },
  "404": { name:"Kenya",          capital:"Nairobi",             iso2:"ke", continent:"africa", summary:"Kenya is East Africa's largest economy and home to world-famous wildlife in the Masai Mara, Amboseli and Tsavo. It is a hub for technology and innovation (the 'Silicon Savannah'). Kenya is also renowned for its long-distance runners." },
  "426": { name:"Lesotho",        capital:"Maseru",              iso2:"ls", continent:"africa", summary:"Lesotho is a small kingdom entirely surrounded by South Africa, one of only three such enclaved countries in the world. Known as 'the Mountain Kingdom', it sits at a high altitude and is the only country entirely above 1,000 metres. It relies heavily on water exports to South Africa." },
  "430": { name:"Liberia",        capital:"Monrovia",            iso2:"lr", continent:"africa", summary:"Liberia is a West African country founded in 1847 by freed American slaves, making it Africa's first republic. Its capital Monrovia is named after US President James Monroe. The country rebuilt after devastating civil wars in the 1990s and 2000s." },
  "434": { name:"Libya",          capital:"Tripoli",             iso2:"ly", continent:"africa", summary:"Libya is a North African country rich in oil that has been in turmoil since the NATO-backed uprising in 2011 that toppled Muammar Gaddafi. It has a vast Saharan interior, Greco-Roman ruins at Leptis Magna and a long Mediterranean coastline." },
  "450": { name:"Madagascar",     capital:"Antananarivo",        iso2:"mg", continent:"africa", summary:"Madagascar is the world's fourth-largest island, often called the 'Eighth Continent' due to its extraordinary biodiversity — 90% of its wildlife is found nowhere else on Earth. It is home to lemurs, baobab trees and unique ecosystems." },
  "454": { name:"Malawi",         capital:"Lilongwe",            iso2:"mw", continent:"africa", summary:"Malawi is a small landlocked country in southeastern Africa, nicknamed 'the Warm Heart of Africa' for its friendly people. Lake Malawi (Lake Nyasa) covers a third of the country and contains more fish species than any other lake on Earth." },
  "466": { name:"Mali",           capital:"Bamako",              iso2:"ml", continent:"africa", summary:"Mali is a vast landlocked country in the Sahel region of West Africa. It was home to the great empires of Mali and Songhai, and Timbuktu was once a world centre of Islamic learning. It faces severe jihadist insurgency and has experienced multiple coups." },
  "478": { name:"Mauritania",     capital:"Nouakchott",          iso2:"mr", continent:"africa", summary:"Mauritania is a vast, arid country mostly covered by the Sahara. It was the last country in the world to officially abolish slavery (1981, criminalized in 2007). Nouakchott, one of the world's newest capitals, was built after independence from France in 1960." },
  "480": { name:"Mauritius",      capital:"Port Louis",          iso2:"mu", continent:"africa", summary:"Mauritius is a prosperous Indian Ocean island nation off the coast of Madagascar. It has one of Africa's highest per capita incomes, driven by tourism, textiles and financial services. The dodo bird, now extinct, was native to Mauritius." },
  "504": { name:"Morocco",        capital:"Rabat",               iso2:"ma", continent:"africa", summary:"Morocco is a North African kingdom with a rich Berber, Arab and French cultural heritage. Its imperial cities (Marrakech, Fez, Meknes, Rabat) are iconic. Morocco is the gateway between Africa and Europe and has been the first African country to host a FIFA World Cup." },
  "508": { name:"Mozambique",     capital:"Maputo",              iso2:"mz", continent:"africa", summary:"Mozambique gained independence from Portugal in 1975 and endured a brutal civil war until 1992. It has a 2,500-km Indian Ocean coastline and significant natural gas reserves. Maputo was formerly known as Lourenço Marques." },
  "516": { name:"Namibia",        capital:"Windhoek",            iso2:"na", continent:"africa", summary:"Namibia is a sparsely populated country in southwestern Africa known for the Namib Desert (the world's oldest), incredible wildlife and the iconic red dunes of Sossusvlei. It gained independence from South Africa in 1990." },
  "562": { name:"Niger",          capital:"Niamey",              iso2:"ne", continent:"africa", summary:"Niger is a vast, landlocked Sahel country, the largest in West Africa by area. One of the world's poorest nations, it has major uranium deposits. Niger experienced a military coup in 2023, leading to regional tensions." },
  "566": { name:"Nigeria",        capital:"Abuja",               iso2:"ng", continent:"africa", summary:"Nigeria is Africa's most populous country with over 220 million people and its largest economy. Lagos is Africa's biggest city. Nigeria is rich in oil, cultural diversity (250 ethnic groups), Nollywood films and music (Afrobeats) exported globally." },
  "646": { name:"Rwanda",         capital:"Kigali",              iso2:"rw", continent:"africa", summary:"Rwanda, 'the land of a thousand hills', has achieved one of Africa's most remarkable economic transformations since the 1994 genocide that killed 800,000 people. Kigali is one of Africa's cleanest and safest cities. Plastic bags are banned nationwide." },
  "678": { name:"São Tomé and Príncipe", capital:"São Tomé",    iso2:"st", continent:"africa", summary:"São Tomé and Príncipe is a small island nation in the Gulf of Guinea, a former Portuguese colony. It is one of Africa's smallest and least populated countries. Its volcanic islands have spectacular scenery and it is known for premium cocoa." },
  "686": { name:"Senegal",        capital:"Dakar",               iso2:"sn", continent:"africa", summary:"Senegal is West Africa's most stable democracy, never having experienced a coup. Its capital Dakar, on the westernmost tip of the African continent, is a major cultural and artistic hub. Senegal is known for its wrestling tradition, Teranga (hospitality) and vibrant music." },
  "694": { name:"Sierra Leone",   capital:"Freetown",            iso2:"sl", continent:"africa", summary:"Sierra Leone is a West African country that endured a devastating civil war from 1991 to 2002. Freetown was founded in 1787 as a settlement for freed slaves. The country has significant diamond deposits and incredible beaches along its Atlantic coast." },
  "706": { name:"Somalia",        capital:"Mogadishu",           iso2:"so", continent:"africa", summary:"Somalia has been without a functioning central government for much of the time since 1991 and suffers from one of the world's worst humanitarian crises. It has the longest coastline in mainland Africa. Al-Shabaab remains a significant threat to stability." },
  "710": { name:"South Africa",   capital:"Pretoria",            iso2:"za", continent:"africa", summary:"South Africa is the continent's most industrialized economy. It ended apartheid in 1994 with Nelson Mandela becoming its first democratically elected president. The 'Rainbow Nation' has 11 official languages, Table Mountain, spectacular wildlife and world-class wine regions." },
  "728": { name:"South Sudan",    capital:"Juba",                iso2:"ss", continent:"africa", summary:"South Sudan became the world's newest country in 2011 when it gained independence from Sudan after a decades-long civil war. It descended into its own civil war in 2013. Despite vast oil reserves it remains one of the world's least developed nations." },
  "729": { name:"Sudan",          capital:"Khartoum",            iso2:"sd", continent:"africa", summary:"Sudan is a northeastern African country where the Blue and White Nile rivers meet at its capital Khartoum. It has been torn by civil conflict since 2023. The ancient Nubian pyramids at Meroë are among Africa's most impressive archaeological sites." },
  "748": { name:"Eswatini",       capital:"Mbabane",             iso2:"sz", continent:"africa", summary:"Eswatini (formerly Swaziland) is a small landlocked kingdom in southern Africa, one of the world's last absolute monarchies under King Mswati III. It changed its name in 2018 on the 50th anniversary of its independence from Britain." },
  "834": { name:"Tanzania",       capital:"Dodoma",              iso2:"tz", continent:"africa", summary:"Tanzania is home to Kilimanjaro (Africa's highest peak), the Serengeti, Ngorongoro Crater and the Zanzibar Archipelago. The country has one of Africa's largest and most diverse wildlife populations. Swahili is co-official with English." },
  "768": { name:"Togo",           capital:"Lomé",                iso2:"tg", continent:"africa", summary:"Togo is a narrow West African country stretching 600km from the Sahel to the Gulf of Guinea. Lomé is known for its Grand Marché and voodoo practices. Togo has one of Africa's busiest ports and a significant phosphate industry." },
  "788": { name:"Tunisia",        capital:"Tunis",               iso2:"tn", continent:"africa", summary:"Tunisia was the birthplace of the Arab Spring in 2010–2011. It has the northernmost point in Africa and a Mediterranean coast lined with Roman ruins (Carthage) and beach resorts. Tunisia is the most progressive Arab country for women's rights." },
  "800": { name:"Uganda",         capital:"Kampala",             iso2:"ug", continent:"africa", summary:"Uganda is a landlocked East African country known as the 'Pearl of Africa'. It has half the world's remaining mountain gorillas, is the source of the Nile and has one of Africa's youngest populations. It has been led by Yoweri Museveni since 1986." },
  "894": { name:"Zambia",         capital:"Lusaka",              iso2:"zm", continent:"africa", summary:"Zambia is a landlocked country in southern Africa, home to the majestic Victoria Falls (shared with Zimbabwe), one of the world's largest waterfalls. It is a major copper producer and has one of Africa's fastest-growing economies." },
  "716": { name:"Zimbabwe",       capital:"Harare",              iso2:"zw", continent:"africa", summary:"Zimbabwe is a landlocked southern African country known for the ancient stone city of Great Zimbabwe, Victoria Falls and its wildlife. It experienced hyperinflation under Robert Mugabe and is still recovering economically." },

  "732": { name:"Western Sahara",  capital:"El Aaiún",           iso2:"eh", continent:"africa", summary:"Western Sahara is a disputed territory on the northwest coast of Africa, largely controlled by Morocco since 1975 when Spain withdrew. The Sahrawi Arab Democratic Republic (SADR) claims sovereignty and is recognized by many African nations, but Morocco administers most of the territory." },
  "690": { name:"Seychelles",      capital:"Victoria",            iso2:"sc", continent:"africa", summary:"Seychelles is a small archipelago nation in the Indian Ocean northeast of Madagascar, comprising 115 islands. It has the smallest population of any African country and one of its highest per capita incomes, driven by tourism and fishing. Victoria is the world's smallest capital city." },

  // ─── ASIA ─────────────────────────────────────
  "4":   { name:"Afghanistan",    capital:"Kabul",               iso2:"af", continent:"asia", summary:"Afghanistan is a landlocked country at the crossroads of Central and South Asia with a history of invasions and empires. After 20 years of US-led military presence, the Taliban regained control in August 2021. It has some of the world's richest mineral deposits still largely unexploited." },
  "51":  { name:"Armenia",        capital:"Yerevan",             iso2:"am", continent:"asia", summary:"Armenia is a landlocked country in the South Caucasus, one of the world's oldest civilizations. It was the first country to adopt Christianity as its state religion (301 AD). Armenia and Azerbaijan fought wars over the Nagorno-Karabakh region in 1991–94 and 2020." },
  "31":  { name:"Azerbaijan",     capital:"Baku",                iso2:"az", continent:"asia", summary:"Azerbaijan is a South Caucasus nation on the Caspian Sea. Baku, one of the oldest cities on the Silk Road, is known for its flame-shaped skyscrapers and ancient walled city. Azerbaijan is rich in oil and gas and hosted the COP29 climate summit in 2024." },
  "48":  { name:"Bahrain",        capital:"Manama",              iso2:"bh", continent:"asia", summary:"Bahrain is a small island kingdom in the Persian Gulf, the first Gulf state to discover oil in 1932. It is a major financial centre and hosts the US Fifth Fleet. Bahrain has been a bridge between the Arab world and Asia for millennia." },
  "50":  { name:"Bangladesh",     capital:"Dhaka",               iso2:"bd", continent:"asia", summary:"Bangladesh is one of the world's most densely populated countries, home to 170 million people. It gained independence from Pakistan in 1971. A major garment manufacturer, it has achieved impressive reductions in poverty and improvements in health outcomes." },
  "64":  { name:"Bhutan",         capital:"Thimphu",             iso2:"bt", continent:"asia", summary:"Bhutan is a small Himalayan kingdom that measures its success by Gross National Happiness rather than GDP. Television was only introduced in 1999. Bhutan is carbon negative, the only country in the world that absorbs more CO₂ than it produces." },
  "96":  { name:"Brunei",         capital:"Bandar Seri Begawan", iso2:"bn", continent:"asia", summary:"Brunei is a small oil-rich sultanate on the island of Borneo governed by Sultan Hassanal Bolkiah, one of the world's wealthiest rulers. Oil revenues provide citizens with free education, healthcare and no income tax." },
  "116": { name:"Cambodia",       capital:"Phnom Penh",          iso2:"kh", continent:"asia", summary:"Cambodia is home to the magnificent Angkor Wat, the world's largest religious monument. The country is still recovering from the Khmer Rouge genocide (1975–79) that killed up to 2 million people. Tourism and garment manufacturing are the key industries." },
  "156": { name:"China",          capital:"Beijing",             iso2:"cn", continent:"asia", summary:"China is the world's most populous country (1.4 billion people) and the second-largest economy. Its civilization is over 5,000 years old. China is the world's largest manufacturer, exporter and holder of foreign exchange reserves. The Great Wall, the Terracotta Army and the Forbidden City are iconic landmarks." },
  "356": { name:"India",          capital:"New Delhi",           iso2:"in", continent:"asia", summary:"India is the world's most populous democracy with 1.4 billion people and a civilization dating back 5,000 years. It has the world's third-largest economy by PPP. Famous for the Taj Mahal, Bollywood, cricket and a vibrant tech industry centred in Bangalore." },
  "360": { name:"Indonesia",      capital:"Jakarta",             iso2:"id", continent:"asia", summary:"Indonesia is the world's largest archipelago nation with over 17,000 islands and the fourth most populous country. It has the world's largest Muslim population. The capital is being relocated from Jakarta to Nusantara on Borneo due to sinking land and overcrowding." },
  "364": { name:"Iran",           capital:"Tehran",              iso2:"ir", continent:"asia", summary:"Iran, ancient Persia, has one of the world's oldest civilizations. It is a major oil producer and regional power in the Middle East. Since the 1979 Islamic Revolution it has been an Islamic Republic. Iran has magnificent UNESCO sites including Persepolis." },
  "368": { name:"Iraq",           capital:"Baghdad",             iso2:"iq", continent:"asia", summary:"Iraq is home to ancient Mesopotamia, widely considered the cradle of civilization where writing was invented. Baghdad was once the largest city in the world and centre of the Islamic Golden Age. Iraq is a major oil producer with a complex sectarian political structure." },
  "376": { name:"Israel",         capital:"Jerusalem",           iso2:"il", continent:"asia", summary:"Israel is a small but highly developed Middle Eastern country established in 1948. Jerusalem, holy to three religions, is the declared capital. Israel has a thriving high-tech sector, Nobel Prize winners and a complex relationship with Palestinian territories." },
  "392": { name:"Japan",          capital:"Tokyo",               iso2:"jp", continent:"asia", summary:"Japan is an East Asian island nation that transformed itself from feudalism to become the world's third-largest economy. Known for technology, anime, manga, bushido culture, cherry blossoms and extraordinary cuisine. Tokyo is the world's largest metropolitan area." },
  "400": { name:"Jordan",         capital:"Amman",               iso2:"jo", continent:"asia", summary:"Jordan is a small, stable Middle Eastern kingdom. It is home to Petra, the magnificent rose-red Nabataean city carved into rock, and the Dead Sea (the world's lowest point on land). Jordan has hosted millions of Syrian refugees since 2011." },
  "398": { name:"Kazakhstan",     capital:"Astana",              iso2:"kz", continent:"asia", summary:"Kazakhstan is the world's largest landlocked country and the ninth-largest overall. A former Soviet republic, it has vast oil, gas and mineral reserves. Astana (formerly Nur-Sultan) was built from scratch as the capital in 1997 and features futuristic architecture." },
  "414": { name:"Kuwait",         capital:"Kuwait City",         iso2:"kw", continent:"asia", summary:"Kuwait is a small but extraordinarily oil-rich emirate at the top of the Persian Gulf. It was invaded by Iraq in 1990, triggering the Gulf War. Kuwait has one of the world's highest per capita incomes and citizens pay no income tax." },
  "417": { name:"Kyrgyzstan",     capital:"Bishkek",             iso2:"kg", continent:"asia", summary:"Kyrgyzstan is a landlocked Central Asian nation in the Tian Shan mountains, known for its nomadic heritage, epic landscape and the Kyrgyz epic poem Manas—one of the world's longest. It is one of Central Asia's most democratic countries." },
  "418": { name:"Laos",           capital:"Vientiane",           iso2:"la", continent:"asia", summary:"Laos is the only landlocked country in Southeast Asia. It is the most heavily bombed country in history per capita (US bombing during the Vietnam War era). A one-party communist state, it is known for Buddhist temples, slow-paced river life and unspoilt nature." },
  "422": { name:"Lebanon",        capital:"Beirut",              iso2:"lb", continent:"asia", summary:"Lebanon is a small but diverse Mediterranean country in the Middle East. Beirut was once the 'Paris of the Middle East'. The country faces deep political sectarianism, economic collapse and was devastated by the 2020 port explosion." },
  "458": { name:"Malaysia",       capital:"Kuala Lumpur",        iso2:"my", continent:"asia", summary:"Malaysia is a multicultural Southeast Asian nation divided between the Malay Peninsula and East Malaysia on Borneo. Kuala Lumpur is known for the Petronas Twin Towers. Malaysia is a major exporter of palm oil, rubber and electronics." },
  "462": { name:"Maldives",       capital:"Malé",                iso2:"mv", continent:"asia", summary:"The Maldives is a low-lying tropical archipelago in the Indian Ocean known for its turquoise waters and luxury resorts. It is one of the world's most threatened countries from rising sea levels due to climate change." },
  "496": { name:"Mongolia",       capital:"Ulaanbaatar",         iso2:"mn", continent:"asia", summary:"Mongolia is a vast, sparsely populated landlocked country between Russia and China, home of Genghis Khan's empire, the largest contiguous land empire in history. It still has a strong nomadic tradition and extraordinary steppe and Gobi Desert landscapes." },
  "104": { name:"Myanmar",        capital:"Naypyidaw",           iso2:"mm", continent:"asia", summary:"Myanmar (Burma) is a Southeast Asian country with over 135 ethnic groups. A military coup in February 2021 ended a brief democratic transition. The country has jade, gems and a significant Buddhist cultural heritage including Bagan's ancient temples." },
  "524": { name:"Nepal",          capital:"Kathmandu",           iso2:"np", continent:"asia", summary:"Nepal is home to the Himalayas, including Mount Everest (8,848m), the world's highest peak. It is a multi-ethnic Hindu kingdom that became a republic in 2008. Kathmandu is a vibrant cultural city with medieval temples and a UNESCO-listed valley." },
  "408": { name:"North Korea",    capital:"Pyongyang",           iso2:"kp", continent:"asia", summary:"North Korea (DPRK) is the world's most secretive and isolated state, a totalitarian dictatorship under the Kim dynasty since 1948. It has developed nuclear weapons despite international sanctions. Little is known about daily life inside the country." },
  "512": { name:"Oman",           capital:"Muscat",              iso2:"om", continent:"asia", summary:"Oman is a Gulf Sultanate on the Arabian Peninsula with a history of maritime trading empire. It is known for its frankincense production, dramatic mountains, desert and coastline. Under Sultan Qaboos (1970–2020) it transformed from an impoverished state to a modern nation." },
  "586": { name:"Pakistan",       capital:"Islamabad",           iso2:"pk", continent:"asia", summary:"Pakistan was created in 1947 following partition from British India. It is the world's fifth most populous country and the second-largest Muslim-majority nation. It has nuclear weapons, the K2 mountain and faces significant political instability." },
  "275": { name:"Palestine",      capital:"Ramallah",            iso2:"ps", continent:"asia", summary:"Palestine refers to the Palestinian territories of the West Bank and Gaza Strip. The Palestinian Authority administers parts of the West Bank from Ramallah. Gaza has been under Hamas control since 2007 and suffered devastating war in 2023–2024." },
  "608": { name:"Philippines",    capital:"Manila",              iso2:"ph", continent:"asia", summary:"The Philippines is an archipelago of over 7,000 islands in Southeast Asia. A former US colony, it is the world's third-largest English-speaking country. Known for its vibrant culture, beautiful beaches, Jeepneys and a massive overseas worker diaspora." },
  "634": { name:"Qatar",          capital:"Doha",                iso2:"qa", continent:"asia", summary:"Qatar is a small peninsula in the Persian Gulf with the world's highest GDP per capita thanks to massive natural gas reserves. It hosted the 2022 FIFA World Cup, the first Arab country to do so. It is home to the Al Jazeera media network." },
  "682": { name:"Saudi Arabia",   capital:"Riyadh",              iso2:"sa", continent:"asia", summary:"Saudi Arabia is the world's largest oil exporter and a key player in global energy markets. Custodian of the holy cities of Mecca and Medina, it is the heartland of Islam. Vision 2030 is an ambitious programme to diversify its economy beyond oil." },
  "702": { name:"Singapore",      capital:"Singapore",           iso2:"sg", continent:"asia", summary:"Singapore is a tiny city-state island at the tip of the Malay Peninsula, one of the world's most prosperous nations. It is a global financial hub, major shipping port and is known for its cleanliness, efficiency and multicultural society." },
  "410": { name:"South Korea",    capital:"Seoul",               iso2:"kr", continent:"asia", summary:"South Korea is an East Asian nation that rose from the ashes of the Korean War to become the world's 12th-largest economy. Seoul is a high-tech megacity. South Korea exports Kia/Hyundai cars, Samsung electronics and the global phenomenon of K-pop and K-dramas." },
  "144": { name:"Sri Lanka",      capital:"Sri Jayawardenepura Kotte", iso2:"lk", continent:"asia", summary:"Sri Lanka (formerly Ceylon) is a teardrop-shaped island in the Indian Ocean known for tea, Buddhism, elephants and ancient ruins. It suffered a devastating 26-year civil war ending in 2009 and an economic crisis in 2022." },
  "760": { name:"Syria",          capital:"Damascus",            iso2:"sy", continent:"asia", summary:"Syria is home to one of humanity's oldest civilizations. Damascus is one of the world's oldest continuously inhabited cities. The country has been torn by civil war since 2011, creating one of the world's worst refugee crises. The Assad regime fell in late 2024." },
  "762": { name:"Tajikistan",     capital:"Dushanbe",            iso2:"tj", continent:"asia", summary:"Tajikistan is a mountainous landlocked country in Central Asia. It is the smallest Central Asian country but has over 90% mountainous terrain. The Pamirs, known as 'the Roof of the World', are a major geographic feature. It is the region's poorest economy." },
  "764": { name:"Thailand",       capital:"Bangkok",             iso2:"th", continent:"asia", summary:"Thailand, the 'Land of Smiles', is Southeast Asia's second-largest economy. Bangkok is a vibrant megalopolis with magnificent temples, street food and nightlife. Thailand was never colonized and is known for its monarchy, Buddhism and tourism." },
  "626": { name:"Timor-Leste",    capital:"Dili",                iso2:"tl", continent:"asia", summary:"Timor-Leste (East Timor) is Asia's newest nation, gaining full independence in 2002 after centuries of Portuguese colonialism and 24 years of brutal Indonesian occupation. It has significant offshore oil and gas reserves." },
  "792": { name:"Turkey",         capital:"Ankara",              iso2:"tr", continent:"asia", summary:"Turkey spans two continents — Europe and Asia — and has been a crossroads of civilizations for millennia. Istanbul, the only city on two continents, was ancient Constantinople. Turkey is a NATO member, major regional power and a key link between Europe and the Middle East." },
  "795": { name:"Turkmenistan",   capital:"Ashgabat",            iso2:"tm", continent:"asia", summary:"Turkmenistan is a Central Asian nation with vast natural gas reserves, the world's fourth-largest. It is one of the world's most closed and authoritarian states. Ashgabat is filled with white marble buildings and holds the Guinness record for the world's largest architectural complex of buildings covered in white marble." },
  "784": { name:"United Arab Emirates", capital:"Abu Dhabi",     iso2:"ae", continent:"asia", summary:"The UAE is a federation of seven emirates including Dubai and Abu Dhabi. Oil wealth has transformed it into a global hub for trade, tourism, finance and aviation. Dubai is home to the Burj Khalifa (world's tallest building) and the Palm Jumeirah." },
  "860": { name:"Uzbekistan",     capital:"Tashkent",            iso2:"uz", continent:"asia", summary:"Uzbekistan is a doubly landlocked Central Asian country on the ancient Silk Road. Cities like Samarkand and Bukhara were major Islamic centres of learning. Under Tamerlane (Timur) it was the heart of a great empire. It has significant gold, natural gas and cotton industries." },
  "704": { name:"Vietnam",        capital:"Hanoi",               iso2:"vn", continent:"asia", summary:"Vietnam is a Southeast Asian nation with a 4,000-year history that has overcome devastating wars against France (1954) and the US (1975) to become one of Asia's fastest-growing economies. It is a major electronics manufacturer and producer of coffee and seafood." },
  "887": { name:"Yemen",          capital:"Sanaa",               iso2:"ye", continent:"asia", summary:"Yemen is a country on the Arabian Peninsula experiencing one of the world's worst humanitarian crises. A civil war since 2015, involving a Saudi-led coalition and Houthi rebels, has killed hundreds of thousands. Ancient Sanaa, a UNESCO World Heritage Site, is one of the world's oldest cities." },
  // ─── AMERICAS ─────────────────────────────────
  "28":  { name:"Antigua and Barbuda", capital:"Saint John's",  iso2:"ag", continent:"america", summary:"Antigua and Barbuda is a twin-island nation in the Caribbean, known for its 365 beaches (one for each day of the year). It gained independence from Britain in 1981 and is known for sailing, cricket and spectacular reefs." },
  "32":  { name:"Argentina",      capital:"Buenos Aires",        iso2:"ar", continent:"america", summary:"Argentina is South America's second-largest country, a land of the Andes, Patagonia, the Pampas and Iguazú Falls. Buenos Aires, 'the Paris of South America', has a vibrant tango and literary culture. Argentina is a major agricultural exporter and World Cup champion (2022)." },
  "44":  { name:"Bahamas",        capital:"Nassau",              iso2:"bs", continent:"america", summary:"The Bahamas is an archipelago of 700 islands and cays in the Atlantic Ocean north of Cuba. Independent since 1973, it is a major tourist destination and offshore financial centre known for its clear turquoise waters." },
  "52":  { name:"Barbados",       capital:"Bridgetown",          iso2:"bb", continent:"america", summary:"Barbados is a small Caribbean island nation that gained independence from Britain in 1966 and became a republic in 2021. Known for cricket, rum (Banks and Mount Gay), beautiful beaches and the birthplace of Rihanna." },
  "84":  { name:"Belize",         capital:"Belmopan",            iso2:"bz", continent:"america", summary:"Belize is a small Central American country on the Caribbean coast, the only English-speaking country in Central America. It has the second-largest barrier reef in the world, Mayan ruins and incredible biodiversity." },
  "68":  { name:"Bolivia",        capital:"Sucre",               iso2:"bo", continent:"america", summary:"Bolivia is a landlocked South American nation with stunning geography: the Andes, the Amazon, the Atacama and the altiplano. La Paz is the world's highest capital city. The country has the world's largest salt flat (Salar de Uyuni) and major lithium reserves." },
  "76":  { name:"Brazil",         capital:"Brasília",            iso2:"br", continent:"america", summary:"Brazil is the world's fifth-largest country and South America's giant — the Amazon rainforest, 2,200km of beaches, Carnival in Rio de Janeiro and a record-breaking 5 FIFA World Cup titles. São Paulo is Latin America's largest city and financial hub." },
  "124": { name:"Canada",         capital:"Ottawa",              iso2:"ca", continent:"america", summary:"Canada is the world's second-largest country by area, known for its multiculturalism, stunning landscapes (Rockies, Arctic, Great Lakes), ice hockey, maple syrup and consistently high quality of life rankings." },
  "152": { name:"Chile",          capital:"Santiago",            iso2:"cl", continent:"america", summary:"Chile is a long, thin country stretching 4,300km down South America's Pacific coast. It encompasses Patagonia, the Atacama Desert (world's driest), Easter Island and the Andes. Chile is the world's largest copper producer and a major wine exporter." },
  "170": { name:"Colombia",       capital:"Bogotá",              iso2:"co", continent:"america", summary:"Colombia is the only South American country with both Pacific and Caribbean coasts. Once synonymous with drug cartels, it has transformed into an emerging economy known for coffee, flowers, cumbia music, biodiversity and tourist destinations like Cartagena." },
  "188": { name:"Costa Rica",     capital:"San José",            iso2:"cr", continent:"america", summary:"Costa Rica is a Central American pioneer in ecotourism and environmental conservation. It has no army (abolished in 1948) and runs on nearly 100% renewable energy. It is known for incredible biodiversity — 5% of the world's species in 0.03% of its area." },
  "192": { name:"Cuba",           capital:"Havana",              iso2:"cu", continent:"america", summary:"Cuba is the Caribbean's largest island and the only communist state in the Western Hemisphere. Havana, with its colourful 1950s American cars and Spanish colonial architecture, is iconic. Cuba is known for its free healthcare, cigars and salsa music." },
  "212": { name:"Dominica",       capital:"Roseau",              iso2:"dm", continent:"america", summary:"Dominica is known as the 'Nature Isle of the Caribbean' for its lush rainforests, volcanic peaks and hot springs. Not to be confused with the Dominican Republic, it is a small island with a largely indigenous Kalinago population." },
  "214": { name:"Dominican Republic", capital:"Santo Domingo",   iso2:"do", continent:"america", summary:"The Dominican Republic shares the island of Hispaniola with Haiti and has the Caribbean's largest economy. Santo Domingo was the first permanent European settlement in the Americas (1498). Known for its beaches, merengue music and baseball." },
  "218": { name:"Ecuador",        capital:"Quito",               iso2:"ec", continent:"america", summary:"Ecuador (named for the equator) encompasses the Andes, the Amazon, the Galápagos Islands and the Pacific coast. The Galápagos inspired Charles Darwin's theory of evolution. Quito, one of South America's best-preserved colonial cities, sits at 2,850m altitude." },
  "222": { name:"El Salvador",    capital:"San Salvador",        iso2:"sv", continent:"america", summary:"El Salvador is the smallest and most densely populated country in Central America. Recovering from a brutal civil war (1979–1992), it has battled gang violence in recent years and became the first country to adopt Bitcoin as legal tender in 2021." },
  "308": { name:"Grenada",        capital:"Saint George's",      iso2:"gd", continent:"america", summary:"Grenada, the 'Island of Spice', is a small Caribbean nation known for producing nutmeg, mace and cinnamon. It gained independence from Britain in 1974. In 1983 the US invaded Grenada following a political crisis and coup." },
  "320": { name:"Guatemala",      capital:"Guatemala City",      iso2:"gt", continent:"america", summary:"Guatemala has the largest population in Central America and an extraordinary Mayan heritage. Tikal, in the jungle, is one of the Americas' greatest ancient cities. The country has significant inequality between its Ladino and indigenous Maya populations." },
  "328": { name:"Guyana",         capital:"Georgetown",          iso2:"gy", continent:"america", summary:"Guyana is the only English-speaking country in South America, a former British colony. It has the largest unspoilt rainforest in the hemisphere relative to its size. Oil was discovered offshore in 2015, rapidly transforming its economy." },
  "332": { name:"Haiti",          capital:"Port-au-Prince",      iso2:"ht", continent:"america", summary:"Haiti was the first Black republic and the first Caribbean nation to gain independence (1804), after the only successful slave revolution in history. It is the poorest country in the Western Hemisphere and has been plagued by earthquakes, hurricanes and political crisis." },
  "340": { name:"Honduras",       capital:"Tegucigalpa",         iso2:"hn", continent:"america", summary:"Honduras is a Central American nation with Caribbean and Pacific coasts. It has significant Mayan heritage (Copán). Honduras faces some of the world's highest homicide rates and has experienced high levels of emigration to the United States." },
  "388": { name:"Jamaica",        capital:"Kingston",            iso2:"jm", continent:"america", summary:"Jamaica is the birthplace of Bob Marley, reggae music and Rastafarianism. It is famous for its Blue Mountains coffee, jerk chicken and sprint runners (Usain Bolt). A British colony until 1962, Jamaica is a member of the Commonwealth." },
  "484": { name:"Mexico",         capital:"Mexico City",         iso2:"mx", continent:"america", summary:"Mexico is North America's southernmost and most populous Spanish-speaking country. Home to ancient civilizations (Aztec, Maya), it has the world's largest Spanish-speaking city in Mexico City. Mexico is famous for tacos, tequila, mariachi and its extraordinary cultural heritage." },
  "558": { name:"Nicaragua",      capital:"Managua",             iso2:"ni", continent:"america", summary:"Nicaragua is Central America's largest country by area. It experienced a Sandinista revolution in 1979 and is now under the authoritarian rule of Daniel Ortega. It is known for its volcanoes, Lake Nicaragua (the only freshwater lake with sharks) and colonial cities." },
  "591": { name:"Panama",         capital:"Panama City",         iso2:"pa", continent:"america", summary:"Panama is Central America's southernmost country, famous for the Panama Canal which connects the Atlantic and Pacific Oceans. The canal handles 5% of world trade. Panama is also known for its biodiversity, banking sector and the distinctive Panama hat (actually from Ecuador)." },
  "600": { name:"Paraguay",       capital:"Asunción",            iso2:"py", continent:"america", summary:"Paraguay is a landlocked South American nation that fought the devastating War of the Triple Alliance (1864–70) in which it lost up to 60% of its population. It is a major producer of soya and hydroelectric power from the Itaipú Dam (once the world's largest)." },
  "604": { name:"Peru",           capital:"Lima",                iso2:"pe", continent:"america", summary:"Peru was the heart of the Inca Empire, the largest pre-Columbian empire in the Americas. Machu Picchu, the ancient Inca citadel, is South America's most iconic archaeological site. Peru is known for its cuisine (ceviche, quinoa) and the Amazon rainforest." },
  "659": { name:"Saint Kitts and Nevis", capital:"Basseterre",   iso2:"kn", continent:"america", summary:"Saint Kitts and Nevis is the smallest sovereign state in the Western Hemisphere by both area and population. It gained independence from Britain in 1983 and is known for its sugar-producing history, Brimstone Hill Fortress and citizenship-by-investment programme." },
  "662": { name:"Saint Lucia",    capital:"Castries",            iso2:"lc", continent:"america", summary:"Saint Lucia is a beautiful Caribbean island nation known for its twin Piton volcanic peaks, lush rainforest and upscale beach resorts. It has produced two Nobel Prize winners, more than any other country per capita." },
  "670": { name:"Saint Vincent and the Grenadines", capital:"Kingstown", iso2:"vc", continent:"america", summary:"Saint Vincent and the Grenadines is an island nation of 32 islands and cays in the Caribbean, known for its sailing, beautiful Grenadines chain and yachting culture." },
  "740": { name:"Suriname",       capital:"Paramaribo",          iso2:"sr", continent:"america", summary:"Suriname is a small South American country and the continent's only Dutch-speaking nation, a former Dutch colony. It has one of the world's highest proportions of rainforest cover. Paramaribo's historic inner city is a UNESCO World Heritage Site." },
  "780": { name:"Trinidad and Tobago", capital:"Port of Spain",  iso2:"tt", continent:"america", summary:"Trinidad and Tobago is a twin-island Caribbean nation known for its vibrant Carnival (birthplace of calypso and steelpan music), oil wealth, diverse cuisine and birdwatching. It is one of the wealthiest Caribbean nations per capita." },
  "840": { name:"United States",  capital:"Washington D.C.",     iso2:"us", continent:"america", summary:"The United States is the world's largest economy and most powerful nation, a federal republic of 50 states. It has the world's most powerful military, dominant cultural exports (Hollywood, pop music, tech) and is home to global companies like Apple, Google and Amazon." },
  "858": { name:"Uruguay",        capital:"Montevideo",          iso2:"uy", continent:"america", summary:"Uruguay is South America's most progressive country, a small, stable democracy between Brazil and Argentina. It was the first country to fully legalise marijuana, is known for beef exports, mate tea and football (2 World Cup titles)." },
  "862": { name:"Venezuela",      capital:"Caracas",             iso2:"ve", continent:"america", summary:"Venezuela holds the world's largest proven oil reserves but has suffered a catastrophic economic and political crisis under Nicolás Maduro, causing over 7 million people to emigrate. It is home to Angel Falls (world's highest waterfall) and the Amazon." },

  // ─── OCEANIA ──────────────────────────────────
  "36":  { name:"Australia",      capital:"Canberra",            iso2:"au", continent:"oceania", summary:"Australia is the world's sixth-largest country by area and the only nation that governs an entire continent. Known for the Great Barrier Reef, Uluru, kangaroos, koalas and the Sydney Opera House. Canberra became capital in 1913 as a compromise between Sydney and Melbourne." },
  "242": { name:"Fiji",           capital:"Suva",                iso2:"fj", continent:"oceania", summary:"Fiji is a South Pacific archipelago of over 330 islands known for its pristine beaches, coral reefs, lush rainforests and friendly people. A British colony until 1970, it is a popular tourist destination and has experienced several military coups." },
  "296": { name:"Kiribati",       capital:"South Tarawa",        iso2:"ki", continent:"oceania", summary:"Kiribati is a Pacific island nation that spans all four hemispheres. Its low-lying atolls make it one of the countries most threatened by rising sea levels. Kiribati was the first country to observe each new year due to its extreme eastern timezone." },
  "584": { name:"Marshall Islands", capital:"Majuro",            iso2:"mh", continent:"oceania", summary:"The Marshall Islands is a Pacific island nation in the central Pacific Ocean. The United States conducted nuclear weapons tests at Bikini Atoll in the 1940s–50s, leaving lasting environmental damage. The country is in free association with the US." },
  "583": { name:"Micronesia",     capital:"Palikir",             iso2:"fm", continent:"oceania", summary:"The Federated States of Micronesia is a Pacific nation of over 600 islands spread across the western Pacific. It has a compact of free association with the US and Palikir on Pohnpei Island serves as its capital." },
  "520": { name:"Nauru",          capital:"Yaren",               iso2:"nr", continent:"oceania", summary:"Nauru is the world's smallest island nation and the third-smallest country in the world. Once one of the wealthiest nations per capita from phosphate mining, those reserves are now exhausted, leaving the island facing serious environmental and economic challenges." },
  "554": { name:"New Zealand",    capital:"Wellington",          iso2:"nz", continent:"oceania", summary:"New Zealand is a Pacific island nation known for stunning landscapes (used for Lord of the Rings), the Maori culture, rugby (All Blacks), geothermal activity and being the first country to give women the vote in 1893." },
  "585": { name:"Palau",          capital:"Ngerulmud",           iso2:"pw", continent:"oceania", summary:"Palau is a Pacific archipelago famed for its extraordinary marine biodiversity. Jellyfish Lake, where millions of golden jellyfish can be swum with safely, is iconic. Palau was one of the first countries to create a marine sanctuary." },
  "598": { name:"Papua New Guinea", capital:"Port Moresby",      iso2:"pg", continent:"oceania", summary:"Papua New Guinea is one of the world's most culturally diverse countries, with over 800 languages. It occupies the eastern half of New Guinea island and is home to extraordinary biodiversity. Much of the country is still covered in pristine rainforest." },
  "882": { name:"Samoa",          capital:"Apia",                iso2:"ws", continent:"oceania", summary:"Samoa is a Polynesian island nation in the South Pacific. It changed its position east of the International Date Line to the west in 2011, becoming one of the first countries to see each new day. Samoa is known for its village-based communal culture (fa'a Samoa)." },
  "90":  { name:"Solomon Islands", capital:"Honiara",            iso2:"sb", continent:"oceania", summary:"The Solomon Islands is a Pacific archipelago nation that was the site of fierce fighting between US and Japanese forces in WWII (Battle of Guadalcanal). It has extraordinary marine biodiversity and continues to have close ties with both Australia and China." },
  "776": { name:"Tonga",          capital:"Nuku'alofa",          iso2:"to", continent:"oceania", summary:"Tonga is the only remaining Polynesian monarchy, ruled by a king. It is the only Pacific nation never colonized by a foreign power. Tonga is known for its rugby players, whale watching and distinctive culture." },
  "798": { name:"Tuvalu",         capital:"Funafuti",            iso2:"tv", continent:"oceania", summary:"Tuvalu is one of the world's smallest and most remote nations, a coral atoll nation facing potential submersion due to rising sea levels. It sold its .tv internet domain for substantial revenue and has explored migration options for its 11,000 citizens." },
  "548": { name:"Vanuatu",        capital:"Port Vila",           iso2:"vu", continent:"oceania", summary:"Vanuatu is a Pacific archipelago of 80 islands known for active volcanoes, bungee jumping (the original, using vines) and extraordinary biodiversity. It regularly ranks as one of the world's happiest countries." }
};

