// Helper: look up country data by topojson feature id
function getCountryData(featureId) {
  const id = String(+featureId); // normalise numeric id
  return COUNTRIES[id] || null;
}

// Helper: look up US state by FIPS
function getStateData(featureId) {
  const id = String(+featureId);
  return US_STATES[id] || null;
}

// Helper: flag image URL
function flagUrl(iso2, size = 80) {
  return `https://flagcdn.com/w${size}/${iso2.toLowerCase()}.png`;
}
